#include<bits/stdc++.h>
using namespace std;
int a[2000010],n;
deque<int> q;
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        a[i+n]=a[i];
    }
    int ans=0;
    for(int i=1;i<=n*2;i++)
    {
        while(!q.empty()&&q.front()<i-n/2)
        {
            q.pop_front();
        }
        if(!q.empty())
        {
            ans=max(ans,a[i]+a[q.front()]+i-q.front());
        }
        while(!q.empty()&&a[q.back()]-q.back()<=a[i]-i)
        {
            q.pop_back();
        }
        q.push_back(i);
    }
    printf("%d",ans);
    return 0;
}
